@startuml

package "com" {
  package "iluwatar" {
    package "multiton" {

      class App {
        {static} -LOGGER : Logger
        --
        + App()
        + {static} main(args : String[])
      }

      class Nazgul {
        - name : NazgulName
        {static} - nazguls : Map<NazgulName, Nazgul>
        --
        - Nazgul(name : NazgulName)
        + {static} getInstance(name : NazgulName) : Nazgul
        + getName() : NazgulName
      }

      enum NazgulName {
        ADUNAPHEL
        AKHORAHIL
        DWAR
        HOARMURATH
        JI_INDUR
        KHAMUL
        MURAZOR
        REN
        UVATHA
        --
        + {static} valueOf(name : String) : NazgulName
        + {static} values() : NazgulName[]
      }

      Nazgul --> NazgulName : -name

    }
  }
}

@enduml
